// Final Resilient Mapping with ALL required fields
const input = $input.first().json;

// Extract values directly from root
const clientName = input['Client Full Name'] || 'Valued Client';
const companyName = input['Company Name'] || 'Your Company';
const clientEmail = input['Client Email'] || 'spsiddarthan17@gmail.com';
const budgetAgreed = input['Budget / Pricing Agreed'] || '0';
const timeline = input['Timeline'] || 'TBD';
const goals = input['Key Goals / Requirements'] || 'Not specified';
const additionalNotes = input['Additional Notes'] || '';
const preferredLanguage = input['Preferred Language'] || 'English';
const industry = input['Industry / Niche'] || 'General';
const serviceType = input['Service Requested'] || 'Consulting';

// Handle currency formatting
const budget = parseFloat(String(budgetAgreed).replace(/[^0-9.]/g, '')) || 0;
const gst = budget * 0.18;
const totalWithGST = budget + gst;
const proposalSuffix = Math.floor(Math.random() * 100000);

// Calculate due date (30 days from now)
const today = new Date();
const dueDate = new Date(today.getTime() + 30 * 24 * 60 * 60 * 1000);
const dueDateFormatted = dueDate.toLocaleDateString('en-IN');
const dateCreated = today.toLocaleDateString('en-IN');

return [{
  json: {
    clientName,
    companyName,
    clientEmail,
    industry,
    serviceType,
    timeline,
    goals,
    additionalNotes,
    preferredLanguage,
    budget,
    budgetFormatted: 'â‚¹' + budget.toLocaleString('en-IN'),
    gst,
    gstFormatted: 'â‚¹' + gst.toLocaleString('en-IN'),
    totalWithGST,
    totalFormatted: 'â‚¹' + totalWithGST.toLocaleString('en-IN'),
    proposalId: 'PROP-' + proposalSuffix,
    invoiceId: 'INV-' + proposalSuffix,
    dateCreated,
    dueDate: dueDateFormatted,
    emailSubject: 'Tailored Proposal â€” ' + companyName,
    acceptUrl: 'https://n8n.pureremedysolutions.com/webhook/proposal-accept?proposalId=PROP-' + proposalSuffix,
    declineUrl: 'https://n8n.pureremedysolutions.com/webhook/proposal-decline?proposalId=PROP-' + proposalSuffix,
    systemPrompt: 'You are a professional business proposal writer. Generate compelling, professional proposal content. Respond with valid JSON only, no markdown code blocks. The JSON should have these exact keys: executive_summary, why_choose_us, our_approach, scope_of_work, deliverables_timeline, expected_outcomes, investment_justification, competitive_positioning. Each value should be a detailed paragraph or bullet points as a string.',
    userPrompt: `Create a professional business proposal for ${companyName} in the ${industry} industry. They need ${serviceType} services with a budget of â‚¹${budget.toLocaleString('en-IN')} and timeline of ${timeline}. Their key goals are: ${goals}. Additional notes: ${additionalNotes}. Make it compelling and professional.`,
    debug_keys: Object.keys(input)
  }
}];

const aiResponse = $input.first().json;
const formData = $('ðŸ”§ Parse & Prepare').first().json;

let aiContent;
try {
  let raw = '';
  if (aiResponse.choices && aiResponse.choices[0] && aiResponse.choices[0].message) {
    raw = aiResponse.choices[0].message.content;
  } else if (aiResponse.message && aiResponse.message.content) {
    raw = aiResponse.message.content;
  } else if (aiResponse.text) {
    raw = aiResponse.text;
  } else if (typeof aiResponse.content === 'string') {
    raw = aiResponse.content;
  } else if (typeof aiResponse === 'string') {
    raw = aiResponse;
  } else {
    raw = JSON.stringify(aiResponse);
  }

  // Clean up markdown code blocks if present
  raw = raw.replace(/```json\s*/gi, '').replace(/```\s*/gi, '').trim();

  // Extract JSON object
  const firstBrace = raw.indexOf('{');
  const lastBrace = raw.lastIndexOf('}');
  if (firstBrace !== -1 && lastBrace !== -1) {
    raw = raw.substring(firstBrace, lastBrace + 1);
  }

  aiContent = JSON.parse(raw);
} catch (e) {
  // Fallback content if AI parsing fails
  aiContent = {
    executive_summary: `We are excited to present this tailored proposal for ${formData.companyName}. With deep expertise in the ${formData.industry} sector, our team has designed a ${formData.serviceType} engagement built around your specific goals: ${formData.goals}. We are confident this partnership will deliver measurable results within ${formData.timeline}, positioning ${formData.companyName} for accelerated growth.`,
    why_choose_us: `1. Industry Expertise: Our team has delivered 50+ successful ${formData.industry} projects.\n2. Proven Methodology: Our structured approach has achieved an average 35% improvement in client KPIs.\n3. Dedicated Support: A named project manager and weekly progress reviews.\n4. Results Guarantee: We tie our deliverables to measurable outcomes.`,
    our_approach: `Phase 1 â€” Discovery (Week 1): Comprehensive audit of ${formData.companyName}'s current state and requirements.\nPhase 2 â€” Strategy (Week 2): Data-driven roadmap development tailored to your goals.\nPhase 3 â€” Execution (Week 3 onward): Implementation with regular checkpoints and adjustments.`,
    scope_of_work: `Our ${formData.serviceType} engagement for ${formData.companyName} includes comprehensive analysis, strategy development, implementation support, and ongoing optimization to achieve your stated goals.`,
    deliverables_timeline: `Week 1-2: Discovery and Analysis\nWeek 3-4: Strategy Development\nWeek 5+: Implementation and Optimization\nTimeline: ${formData.timeline}`,
    expected_outcomes: `Based on our experience in the ${formData.industry} sector, we anticipate significant improvements in your key metrics, enhanced operational efficiency, and measurable progress toward your stated goals.`,
    investment_justification: `Your investment of ${formData.budgetFormatted} represents excellent value considering the comprehensive nature of our ${formData.serviceType} services and the expected ROI based on similar engagements.`,
    competitive_positioning: `Our unique combination of ${formData.industry} expertise, proven methodology, and dedicated support team positions ${formData.companyName} to outperform competitors and capture market opportunities.`
  };
}

